,'s2w_promo_lkp_stg','SUCCESS 217812','success','model',13.497705698013306,'2026-04-09T21:15:39.184122Z','2026-04-09T21:15:52.555939Z','2026-04-09T21:15:39.171704Z','2026-04-09T21:15:39.178259Z',217812,False,'-- Casino FanCash Spins/Spin to Win\nselect \n    distinct\n    a.id as bonus_campaign_id,\n    parse_json(data):Bonus:bonusCode::varchar as bonus_code,\n    try_parse_json(a.data):Bonus:bonusOrigin::varchar as "Bonus Origin",\n    case when pp.casino_segment = \'New\' then \'Acquisition\' else \'Retention\' end as category,\n    pp.description,\n    \'Spin to Win\' as subcategory,\n    \'Spin to Win\' as series\nfrom FBG_SOURCE.OSB_SOURCE.BONUS_CAMPAIGNS as a\ninner join FBG_SOURCE.OSB_SOURCE.F2P_PRIZE_POOL as pp\non substr(regexp_replace(parse_json(a.data):Bonus:bonusCode::string,\'[^0-9]\',\'\'),8) = to_varchar(pp.id)\nwhere parse_json(a.data):Bonus:bonusOrigin::string = \'F2PGAME\'\n\nunion all\n\n-- Casino FanCash Draws\nselect\n    distinct\n    id as bonus_campaign_id,\n    parse_json(data):Bonus:bonusCode::varchar as bonus_code,\n    parse_json(data):Bonus:bonusOrigin::varchar as "Bonus Origin",\n    \'Retention\' as category,\n    parse_json(data):Bonus:name::varchar as description,\n    \'FanCash Draws\' as subcategory,\n    \'FanCash Draws\' as series\nfrom FBG_SOURCE.OSB_SOURCE.BONUS_CAMPAIGNS\nwhere parse_json(data):Bonus:sweeps:maxNumberOfOverallEntries::int > 1\n    and (parse_json(data):Bonus:bonusType::varchar = \'Casino\' or parse_json(data):Bonus:name::varchar like \'%Casino%\')',NULL,'01c399fb-0212-67a8-24dd-070319334b63','Thread-12 (worker)','table','{"_message": "SUCCESS 217812", "code": "SUCCESS", "rows_affected": 217812, "query_id": "01c399fb-0212-67a8-24dd-070319334b63", "rows_inserted": 217812, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.casino_credit_awarded_stg','model.dbt_casino.casino_credit_awarded_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
  current_timestamp::timestamp
,'casino_credit_awarded_stg','SUCCESS 199865672','success','model',52.16343283653259,'2026-04-09T21:15:52.673252Z','2026-04-09T21:16:44.757784Z','2026-04-09T21:15:52.664383Z','2026-04-09T21:15:52.672629Z',199865672,False,'SELECT\n        a.acco_id,\n        j.jurisdiction_code,\n        a.id as account_statements_id,\n        COALESCE(cast(replace(a.ext_bonus_campaign_id,\'\',null) as int),a.bonus_campaign_id) as bonus_campaign_id,\n        nvl(sw.bonus_code, b."Bonus Code") "Bonus Code",\n        nvl(sw.description, b.Description) as "Description",\n        try_parse_json(a.additional_info):bonusOrigin::varchar as "Bonus Origin", \n        nvl(sw.category, b."Bonus Category") as "Bonus Category",\n        nvl(sw.subcategory, b.Subcategory) as "SubCategory",\n        nvl(sw.series, b.Series) as "Series",\n        (convert_timezone(\'UTC\',\'America/Anchorage\',trans_date)) AS date,\n        case when a.trans = \'CASINO_CREDIT_AWARDED\' then \'bonus awarded\'\n             when a.trans = \'CASINO_CREDIT_STAKE\' then \'bonus used\' end as transaction,\n        \'casino_credit\' as promo_type,\n        abs(a.amount) amount,\n        0 as after_tax_amount,\n        a.bet_id,\n        try_parse_json(a.additional_info):accountBonusId::int as account_bonus_id,\n        null as referee_account_id\n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS as a\n    inner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS as j\n    on a.jurisdictions_id = j.id\n    LEFT JOIN FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.BONUS_CATEGORIES AS B\n    ON COALESCE(cast(replace(a.ext_bonus_campaign_id,\'\',null) as int),a.bonus_campaign_id) = b.bonus_campaign_id\n    left join FBG_ANALYTICS.CASINO.s2w_promo_lkp_stg sw\n    on a.bonus_campaign_id = sw.bonus_campaign_id\n    WHERE a.trans in (\'CASINO_CREDIT_AWARDED\',\'CASINO_CREDIT_STAKE\')',NULL,'01c399fb-0212-6b00-24dd-070319338647','Thread-14 (worker)','table','{"_message": "SUCCESS 199865672", "code": "SUCCESS", "rows_affected": 199865672, "query_id": "01c399fb-0212-6b00-24dd-070319338647", "rows_inserted": 199865672, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.free_spin_awarded_stg','model.dbt_casino.free_spin_awarded_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
