,'free_spin_awarded_stg','SUCCESS 194885287','success','model',76.71464920043945,'2026-04-09T21:15:52.677465Z','2026-04-09T21:17:09.167310Z','2026-04-09T21:15:52.669561Z','2026-04-09T21:15:52.675061Z',194885287,False,'SELECT\n        a.acco_id,\n        j.jurisdiction_code,\n        a.id as account_statements_id,\n        COALESCE(cast(replace(a.ext_bonus_campaign_id,\'\',null) as int),a.bonus_campaign_id) as bonus_campaign_id,\n        nvl(sw.bonus_code, b."Bonus Code") "Bonus Code",\n        try_parse_json(a.additional_info):bonusOrigin::varchar as "Bonus Origin",\n        nvl(sw.description, b.Description) as "Description",\n        nvl(sw.category, b."Bonus Category") as "Bonus Category",\n        nvl(sw.subcategory, b.Subcategory) as "SubCategory",\n        nvl(sw.series, b.Series) as "Series",\n        (convert_timezone(\'UTC\',\'America/Anchorage\',trans_date)) AS date,\n        case when a.trans = \'FREE_SPIN_AWARDED\' then \'bonus awarded\'\n             when a.trans = \'FREE_SPIN_STAKE\' then \'bonus used\' end as transaction,\n        \'free_spin\' as promo_type,\n        abs(a.amount) amount,\n        0 as after_tax_amount,\n        a.bet_id,\n        try_parse_json(a.additional_info):accountBonusId::int as account_bonus_id,\n        r.referee_account_id\n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS as a\n    inner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS as j\n        on a.jurisdictions_id = j.id\n    LEFT JOIN FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.BONUS_CATEGORIES AS B\n    ON COALESCE(cast(replace(a.ext_bonus_campaign_id,\'\',null) as int),a.bonus_campaign_id) = b.bonus_campaign_id\n    left join FBG_ANALYTICS.CASINO.s2w_promo_lkp_stg sw\n    on a.bonus_campaign_id = sw.bonus_campaign_id\n    left join FBG_P13N.PROMO_BRONZE_TABLE.RAF_REFEREE_BONUSES r\n    on try_parse_json(a.additional_info):accountBonusId::int = cast(r.account_bonus_id as int)\n    WHERE a.trans in (\'FREE_SPIN_AWARDED\',\'FREE_SPIN_STAKE\')',NULL,'01c399fb-0212-6cb9-24dd-07031933b41f','Thread-12 (worker)','table','{"_message": "SUCCESS 194885287", "code": "SUCCESS", "rows_affected": 194885287, "query_id": "01c399fb-0212-6cb9-24dd-07031933b41f", "rows_inserted": 194885287, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.osb_bonus_bet_awarded_stg','model.dbt_casino.osb_bonus_bet_awarded_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
