0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.fc_earns_and_burns_stg','model.dbt_casino.fc_earns_and_burns_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
