,'fc_earns_and_burns_stg','SUCCESS 4676410572','success','model',194.33556127548218,'2026-04-09T21:15:52.676314Z','2026-04-09T21:19:06.923858Z','2026-04-09T21:15:52.667089Z','2026-04-09T21:15:52.674195Z',4676410572,False,'select  \n    acco_id,\n    fancash_transaction_id,\n    redeem_txn_id,\n    earn_jurisdiction_code,\n    burn_jurisdiction_code,\n    CASE WHEN e.ledger_entry_reason = \'CASINO_BETTING\' THEN CAST(999999 as varchar)\n            WHEN e.ledger_entry_reason = \'BONUS_SETTLEMENT\' THEN e.earn_bonus_campaign_id\n            WHEN e.ledger_entry_reason = \'GOODWILL_APPEASEMENTS\' THEN CAST(999998 as varchar)\n    END as bonus_campaign_id,\n    CASE WHEN e.ledger_entry_reason = \'CASINO_BETTING\' THEN \'FanCash Casino Base\'\n        WHEN e.earn_category = \'CASINO_MULTIPLIERS\' THEN \'FanCash Segment Multiplier\'\n        WHEN sw.bonus_code is not null then sw.bonus_code\n        WHEN e.ledger_entry_reason = \'BONUS_SETTLEMENT\' THEN bc."Bonus Code"\n        WHEN e.ledger_entry_reason = \'GOODWILL_APPEASEMENTS\' THEN (CAST(parse_json(e.additional_details):source as varchar))\n    END as "Bonus Code",\n    CASE WHEN e.ledger_entry_reason = \'SPORTS_BOOK_BETTING\' THEN \'Retention\'\n        WHEN e.earn_category = \'CASINO_MULTIPLIERS\' THEN \'FanCash Segment Multiplier\'\n        WHEN sw.description is not null then sw.description\n        WHEN e.ledger_entry_reason = \'BONUS_SETTLEMENT\' THEN bc.Description\n        WHEN e.ledger_entry_reason = \'GOODWILL_APPEASEMENTS\' THEN \'CS Bonus\'\n    END as "Description",\n    sw."Bonus Origin", ---NEW \n    CASE WHEN e.ledger_entry_reason = \'CASINO_BETTING\' THEN \'Retention\'\n        WHEN e.earn_category = \'CASINO_MULTIPLIERS\' THEN \'Retention\'\n        when sw.category is not null then sw.category\n        WHEN e.ledger_entry_reason = \'BONUS_SETTLEMENT\' THEN bc."Bonus Category"\n    END as "Bonus Category",\n    CASE WHEN e.ledger_entry_reason = \'CASINO_BETTING\' THEN \'FanCash Casino Base\'\n        WHEN e.earn_category = \'CASINO_MULTIPLIERS\' THEN \'FanCash Segment Multiplier\'\n        WHEN sw.subcategory is not null then sw.subcategory\n        WHEN e.ledger_entry_reason = \'BONUS_SETTLEMENT\' THEN bc.SubCategory\n        WHEN e.ledger_entry_reason = \'GOODWILL_APPEASEMENTS\' THEN (CAST(parse_json(e.additional_details):source as varchar))\n    END AS "SubCategory",\n    case when sw.series is not null then sw.series\n        WHEN e.earn_category = \'CASINO_MULTIPLIERS\' THEN \'FanCash Segment Multiplier\'\n        else \'\' end AS "Series",\n    e.earn_date_alk,\n    e.burn_date_alk,\n    case when e.burn_site <> \'FBG\' then \'Commerce\' else \'FBG\' end burn_site,\n    e.proportional_earn,\n    e.burned_amount,\n    e.burn_pct,\n    e.expiration_date_alk,\n    e.referee_account_id\nfrom FBG_P13N.PROMO_BRONZE_TABLE.FANCASH_EARN_BURN_MAP_UPDATE e\nleft join FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.BONUS_CATEGORIES bc\non e.earn_bonus_campaign_id = bc.bonus_campaign_id\nleft join FBG_ANALYTICS.CASINO.s2w_promo_lkp_stg sw\non e.earn_bonus_campaign_id = sw.bonus_campaign_id\nwhere e.earn_product = \'Casino\' or sw.bonus_campaign_id is not null \n-- F2P details come from manual sheet and may not be up to date, so earn_product may not be up to date',NULL,'01c399fb-0212-6b00-24dd-07031933863b','Thread-13 (worker)','table','{"_message": "SUCCESS 4676410572", "code": "SUCCESS", "rows_affected": 4676410572, "query_id": "01c399fb-0212-6b00-24dd-07031933863b", "rows_inserted": 4676410572, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.fc_jackpots_drops_stg','model.dbt_casino.fc_jackpots_drops_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
  current_timestamp::timestamp
,'fc_jackpots_drops_stg','SUCCESS 16034','success','model',236.59346079826355,'2026-04-09T21:15:39.182071Z','2026-04-09T21:19:35.663165Z','2026-04-09T21:15:39.169419Z','2026-04-09T21:15:39.176552Z',16034,False,'with round_to_bet as (\n    select id, ext_round_id, bet_id, game_id, jurisdictions_id\n    from FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS\n    where game_id is not null\n        and trans = \'STAKE\'\n    qualify row_number() over (partition by ext_round_id order by trans_date asc) = 1\n)\n\nselect \n    fcjp.acco_id,\n    j.jurisdiction_code,\n    a.id as account_statements_id,\n    null as bonus_campaign_id,\n    \'FanCash Jackpot\' as "Bonus Code",\n    \'FanCash Jackpot\' as "Description",\n    \'FanCash Jackpot\' as "Bonus Origin", ---NEW\n    \'Retention\' as "Bonus Category",\n    \'FanCash Jackpot\' as "SubCategory",\n    \'FanCash Jackpot\' as "Series",\n    event_timestamp_alk AS date,\n    \'fancash jackpot winnings\' as transaction,\n    \'fancash_jackpots\' as promo_type,\n    fcjp.win_amount as amount,\n    fcjp.win_amount as after_tax_amount,\n    null as referee_account_id\nfrom FBG_ANALYTICS_ENGINEERING.STAGING.STG_FANCASH_JACKPOT_EVENT_DROP  fcjp\ninner join round_to_bet a\non fcjp.game_round_id::varchar = a.ext_round_id::varchar and fcjp.game_id::varchar = a.game_id::varchar\ninner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS j\non a.jurisdictions_id = j.id',NULL,'01c399fb-0212-6e7d-24dd-070319333e03','Thread-11 (worker)','table','{"_message": "SUCCESS 16034", "code": "SUCCESS", "rows_affected": 16034, "query_id": "01c399fb-0212-6e7d-24dd-070319333e03", "rows_inserted": 16034, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.osb_bonus_bet_payout_stg','model.dbt_casino.osb_bonus_bet_payout_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
  current_timestamp::timestamp
,'osb_bonus_bet_payout_stg','SUCCESS 379956','success','model',108.36238813400269,'2026-04-09T21:18:17.146470Z','2026-04-09T21:20:05.431940Z','2026-04-09T21:18:17.142359Z','2026-04-09T21:18:17.145899Z',379956,False,'WITH generosity_cost as (\n    SELECT\n        wager_id,\n        sum(exp_generosity_cost) as exp_generosity_cost,\n        sum(generosity_cost) as generosity_cost\n    FROM fbg_analytics.product_and_customer.osb_generosity_cost\n    GROUP BY ALL\n),\n\nexpected_bonus_bet_payouts as (\n    select \n        wager_id as bet_id, \n        sum(-expected_ngr_by_legs) expected_payout\n    from FBG_ANALYTICS_ENGINEERING.TRADING.TRADING_SPORTSBOOK_MART sm\n    inner join FBG_ANALYTICS.CASINO.s2w_promo_lkp_stg sw\n    on sm.promotion_id = sw.bonus_campaign_id\n    where is_free_bet_wager = 1\n    group by all\n)\n\nSELECT\n    a.acco_id,\n    j.jurisdiction_code,\n    a.id as account_statements_id,\n    b.bonus_campaign_id,\n    b."Bonus Code",\n    b."Description",\n    b."Bonus Origin",\n    b."Bonus Category",\n    b."SubCategory",\n    b."Series",\n    (convert_timezone(\'UTC\',\'America/Anchorage\',trans_date)) AS date,\n    \'bonus winnings\' as transaction,\n    \'bonus_bet\' as promo_type,\n    a.amount,\n    gc.generosity_cost as after_tax_amount,\n    null as referee_account_id\nFROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS as a\ninner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS as j\non a.jurisdictions_id = j.id\nINNER JOIN FBG_ANALYTICS.CASINO.osb_bonus_bet_awarded_stg AS b\nON a.bet_id = b.bet_id\nLEFT JOIN generosity_cost gc\non a.bet_id = gc.wager_id\nWHERE a.trans in (\'SETTLEMENT\',\'UNSETTLEMENT\')\n    AND (a.bonus_campaign_id <> 22 or a.bonus_campaign_id is null)\n    AND (a.amount <> 0 or gc.generosity_cost <> 0)\n\nunion all\n\nSELECT\n    a.acco_id,\n    j.jurisdiction_code,\n    a.id as account_statements_id,\n    b.bonus_campaign_id,\n    b."Bonus Code",\n    b."Description",\n    b."Bonus Origin",\n    b."Bonus Category",\n    b."SubCategory",\n    b."Series",\n    (convert_timezone(\'UTC\',\'America/Anchorage\',trans_date)) AS date,\n    \'bonus expected winnings\' as transaction,\n    \'bonus_bet\' as promo_type,\n    e.expected_payout as amount,\n    gc.exp_generosity_cost as after_tax_amount,\n    null as referee_account_id\nFROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS as a\ninner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS as j\non a.jurisdictions_id = j.id\nINNER JOIN FBG_ANALYTICS.CASINO.osb_bonus_bet_awarded_stg AS b\nON a.bet_id = b.bet_id\ninner join expected_bonus_bet_payouts e\non a.bet_id = e.bet_id\nLEFT JOIN generosity_cost gc\non a.bet_id = gc.wager_id\nWHERE a.trans in (\'SETTLEMENT\',\'UNSETTLEMENT\')\n    AND (a.bonus_campaign_id <> 22 or a.bonus_campaign_id is null)',NULL,'01c399fe-0212-6dbe-24dd-07031933ce0f','Thread-12 (worker)','table','{"_message": "SUCCESS 379956", "code": "SUCCESS", "rows_affected": 379956, "query_id": "01c399fe-0212-6dbe-24dd-07031933ce0f", "rows_inserted": 379956, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.fc_jackpots_costs_stg','model.dbt_casino.fc_jackpots_costs_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
