,'fc_jackpots_costs_stg','SUCCESS 1118728297','success','model',516.0146956443787,'2026-04-09T21:15:39.186189Z','2026-04-09T21:24:15.098452Z','2026-04-09T21:15:39.167133Z','2026-04-09T21:15:39.180249Z',1118728297,False,'with round_to_bet as (\n    select id, ext_round_id, bet_id, game_id, jurisdictions_id\n    from FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS\n    where game_id is not null\n        and trans = \'STAKE\'\n    qualify row_number() over (partition by ext_round_id order by trans_date asc) = 1\n)\n\nselect \n    fcjp.acco_id,\n    j.jurisdiction_code,\n    a.id as account_statements_id,\n    null as bonus_campaign_id,\n    \'FanCash Jackpot\' as "Bonus Code",\n    \'FanCash Jackpot\' as "Description",\n    \'FanCash Jackpot\' as "Bonus Origin", ---NEW\n    \'Retention\' as "Bonus Category",\n    \'FanCash Jackpot\' as "SubCategory",\n    \'FanCash Jackpot\' as "Series",\n    min(event_timestamp_alk) AS date,\n    \'fancash jackpot contribution\' as transaction,\n    \'fancash_jackpots\' as promo_type,\n    sum(fcjp.contribution_split_current) + sum(fcjp.contribution_split_reserve) as amount,\n    sum(fcjp.contribution_split_current) + sum(fcjp.contribution_split_reserve) as after_tax_amount,\n    null as referee_account_id\nfrom FBG_ANALYTICS_ENGINEERING.STAGING.STG_FANCASH_JACKPOT_EVENT_WAGER fcjp\ninner join round_to_bet a\non fcjp.game_round_id::varchar = a.ext_round_id::varchar and fcjp.game_id::varchar = a.game_id::varchar\ninner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS j\non a.jurisdictions_id = j.id\ngroup by all',NULL,'01c399fb-0212-6dbe-24dd-070319332f63','Thread-10 (worker)','table','{"_message": "SUCCESS 1118728297", "code": "SUCCESS", "rows_affected": 1118728297, "query_id": "01c399fb-0212-6dbe-24dd-070319332f63", "rows_inserted": 1118728297, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.fc_jackpots_awarded_stg','model.dbt_casino.fc_jackpots_awarded_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
  current_timestamp::timestamp
,'fc_jackpots_awarded_stg','SUCCESS 2237456594','success','model',525.8994507789612,'2026-04-09T21:15:39.180675Z','2026-04-09T21:24:24.974155Z','2026-04-09T21:15:39.164709Z','2026-04-09T21:15:39.175597Z',2237456594,False,'WITH transactions_lkp as (--noqa: disable=all\n    select * from (values (\'bonus awarded\'), (\'bonus used\')) as transactions (transaction)\n),\n\nround_to_bet as (\n    select id, ext_round_id, bet_id, game_id, jurisdictions_id\n    from FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS\n    where game_id is not null\n        and trans = \'STAKE\'\n    qualify row_number() over (partition by ext_round_id order by trans_date asc) = 1\n)\n\nselect \n    fcjp.acco_id,\n    j.jurisdiction_code,\n    a.id as account_statements_id,\n    a.bet_id as bet_id,\n    null as bonus_campaign_id,\n    \'FanCash Jackpot\' as "Bonus Code",\n    \'FanCash Jackpot\' as "Description",\n    \'FanCash Jackpot\' as "Bonus Origin", \n    \'Retention\' as "Bonus Category",\n    \'FanCash Jackpot\' as "SubCategory",\n    \'FanCash Jackpot\' as "Series",\n    min(event_timestamp_alk) AS date,\n    t.transaction,\n    case \n        when t.transaction = \'bonus awarded\' then \'fancash\' \n        when t.transaction = \'bonus used\' then \'fancash_jackpots\' end as promo_type,\n    max(fcjp.wager_amount) as amount,\n    sum(0) as after_tax_amount,\n    null as referee_account_id\nfrom FBG_ANALYTICS_ENGINEERING.STAGING.STG_FANCASH_JACKPOT_EVENT_WAGER fcjp\ninner join transactions_lkp t\non 1=1\ninner join round_to_bet a\non fcjp.game_round_id::varchar = a.ext_round_id::varchar and fcjp.game_id::varchar = a.game_id::varchar\ninner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS j\non a.jurisdictions_id = j.id\ngroup by all',NULL,'01c399fb-0212-6cb9-24dd-07031933b2a7','Thread-9 (worker)','table','{"_message": "SUCCESS 2237456594", "code": "SUCCESS", "rows_affected": 2237456594, "query_id": "01c399fb-0212-6cb9-24dd-07031933b2a7", "rows_inserted": 2237456594, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.casino_bet_expected_payouts_stg','model.dbt_casino.casino_bet_expected_payouts_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
  current_timestamp::timestamp
,'casino_bet_expected_payouts_stg','SUCCESS 5883414923','success','model',538.267635345459,'2026-04-09T21:15:39.179076Z','2026-04-09T21:24:37.287595Z','2026-04-09T21:15:39.158241Z','2026-04-09T21:15:39.174868Z',5883414923,False,'with daily_agg as (\n    select \n        acco_id,\n        settled_date_alk,\n        game_id,\n        platform_id,\n        state,\n        sum(cash_bet_stake) cash_bet_stake,\n        sum(freespin_bet_stake) freespin_bet_stake,\n        sum(casino_credit_bet_stake) casino_credit_bet_stake,\n        sum(expected_ggr) expected_ggr,\n        sum(expected_freespin_bet_payout) expected_freespin_bet_payout,\n        sum(expected_casino_credit_bet_payout) expected_casino_credit_bet_payout\n    from FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_DAILY_SETTLED_AGG\n    where is_test_account = 0\n    group by 1,2,3,4,5\n)\n\nselect \n    tm.acco_id,\n    tm.bet_id,\n    tm.bonus_campaign_id,\n    tm.fund_type_id,\n    tm.game_id,\n    tm.ext_game_id,\n    tm.round_id,\n    tm.placed_time_utc,\n    case when tm.fund_type_id = 1 then div0(tm.stake,ds.cash_bet_stake)*(ds.cash_bet_stake - ds.expected_ggr) \n         when tm.fund_type_id = 17 then div0(tm.stake,ds.freespin_bet_stake)*ds.expected_freespin_bet_payout\n         when tm.fund_type_id = 18 then div0(tm.stake,ds.casino_credit_bet_stake)*ds.expected_casino_credit_bet_payout end as expected_payout\nfrom FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_TRANSACTIONS_MART tm\ninner join daily_agg ds\non tm.acco_id = ds.acco_id \n    and tm.settled_time_alk::date = ds.settled_date_alk \n    and tm.game_id = ds.game_id\n    and tm.platform_id = ds.platform_id\n    and tm.jurisdictions_code = ds.state\nwhere tm.test = 0',NULL,'01c399fb-0212-6e7d-24dd-070319333dff','Thread-7 (worker)','table','{"_message": "SUCCESS 5883414923", "code": "SUCCESS", "rows_affected": 5883414923, "query_id": "01c399fb-0212-6e7d-24dd-070319333dff", "rows_inserted": 5883414923, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.fc_costs_stg_incremental','model.dbt_casino.fc_costs_stg_incremental','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
  current_timestamp::timestamp
,'fc_costs_stg_incremental','SUCCESS 9378321','success','model',356.74626302719116,'2026-04-09T21:19:07.007214Z','2026-04-09T21:25:03.639562Z','2026-04-09T21:19:07.000491Z','2026-04-09T21:19:07.006620Z',9378321,False,'with transactions as (\n\nselect  \n    MD5(p.acco_id || \'-\' || COALESCE(p.burn_jurisdiction_code, \'0\') || e.bonus_campaign_id || \'-\' || TO_VARCHAR(CASE WHEN p.burn_site <> \'FBG\' THEN p.burn_date_alk ELSE p.payout_date_alk END, \'YYYY-MM-DD HH24:MI:SS.FF3\') || e."Bonus Code" ) AS fc_burn_id,\n    p.acco_id,\n    p.burn_jurisdiction_code,\n    e.bonus_campaign_id,\n    e."Bonus Code",\n    e."Description",\n    e."Bonus Origin", ---NEW \n    e."Bonus Category",\n    e."SubCategory",\n    e."Series",\n    e.referee_account_id,\n    case when p.burn_site <> \'FBG\' then \'Commerce\' else \'FBG\' end burn_site,\n    CASE WHEN p.burn_site <> \'FBG\' THEN p.burn_date_alk ELSE p.payout_date_alk END as payout_date_alk,\n    sum(p.payout * e.burn_pct) as proportional_payout,\n    sum(p.epayout * e.burn_pct) as proportional_epayout,\n    sum(p.generosity_cost * e.burn_pct) as proportional_generosity_cost,\n    sum(p.exp_generosity_cost * e.burn_pct) as proportional_exp_generosity_cost\nfrom FBG_ANALYTICS.CASINO.fc_earns_and_burns_stg e\ninner join FBG_P13N.PROMO_BRONZE_TABLE.FANCASH_BURN_PAYOUT_MAPPING_UPDATED p\non e.fancash_transaction_id = p.fancash_transaction_id and e.redeem_txn_id = p.redeem_txn_id and e.acco_id = p.acco_id\nwhere 1=1\nand (\n    (p.burn_site <> \'FBG\' AND p.burn_date_alk IS NOT NULL)\n    or (p.burn_site = \'FBG\' AND p.payout_date_alk IS NOT NULL)\n)\n\nand date(greatest_ignore_nulls(p.burn_date_alk, p.payout_date_alk)) >= (SELECT MAX(DATEADD(\'day\', -14, date(payout_date_alk))) FROM FBG_ANALYTICS.CASINO.fc_costs_stg_incremental)\n\ngroup by all\n\n)\n\nselect \n    fc_burn_id,\n    acco_id,\n    burn_jurisdiction_code,\n    bonus_campaign_id,\n    "Bonus Code",\n    "Description",\n    "Bonus Origin",  \n    "Bonus Category",\n    "SubCategory",\n    "Series",\n    referee_account_id,\n    burn_site,\n    payout_date_alk,\n    proportional_payout,\n    proportional_epayout,\n    proportional_generosity_cost,\n    proportional_exp_generosity_cost,\n    CONVERT_TIMEZONE(\'UTC\', CURRENT_TIMESTAMP()) AS insert_timestamp\nfrom transactions',NULL,'01c39a04-0212-67a8-24dd-07031935b237','Thread-14 (worker)','incremental','{"_message": "SUCCESS 9378321", "code": "SUCCESS", "rows_affected": 9378321, "query_id": "01c39a04-0212-67a8-24dd-07031935b237", "rows_inserted": 9378321, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.casino_credit_payout_ratios_stg','model.dbt_casino.casino_credit_payout_ratios_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
  current_timestamp::timestamp
,'casino_credit_payout_ratios_stg','SUCCESS 8578681','success','model',583.2501211166382,'2026-04-09T21:15:39.177193Z','2026-04-09T21:25:22.317684Z','2026-04-09T21:15:39.162247Z','2026-04-09T21:15:39.174276Z',8578681,False,'select \n    id,\n    bet_id,\n    bonus_campaign_id,\n    attrib_perc\nfrom (\n    select \n        distinct\n        id,\n        bet_id, \n        trans,\n        COALESCE(cast(replace(ext_bonus_campaign_id,\'\',null) as int),bonus_campaign_id) as bonus_campaign_id,\n        sum(abs(amount)) over (partition by id,bet_id) / sum(abs(amount)) over (partition by bet_id) attrib_perc \n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS\n    where game_id is not null\n        and trans in (\'STAKE\',\'CASINO_CREDIT_STAKE\')\n        and (( bet_id in ( select bet_id from FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS where game_id is not null and trans = \'STAKE\' )\n                and bet_id in ( select bet_id from FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS where game_id is not null and trans = \'CASINO_CREDIT_STAKE\') )\n            or bet_id in ( select bet_id from \n                            ( select distinct bet_id, sum(1) over (partition by bet_id) as combined_cc_count \n                            from FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS\n                            where game_id is not null and trans = \'CASINO_CREDIT_STAKE\'\n                            qualify combined_cc_count > 1)\n                            )\n            )\n)\nwhere trans = \'CASINO_CREDIT_STAKE\'',NULL,'01c399fb-0212-6e7d-24dd-070319333e07','Thread-8 (worker)','table','{"_message": "SUCCESS 8578681", "code": "SUCCESS", "rows_affected": 8578681, "query_id": "01c399fb-0212-6e7d-24dd-070319333e07", "rows_inserted": 8578681, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.free_spin_payout_stg','model.dbt_casino.free_spin_payout_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
