,'free_spin_payout_stg','SUCCESS 364161931','success','model',133.57618236541748,'2026-04-09T21:24:37.422580Z','2026-04-09T21:26:50.912797Z','2026-04-09T21:24:37.418613Z','2026-04-09T21:24:37.422010Z',364161931,False,'WITH generosity_cost as (\n    SELECT\n        bet_id,\n        bonus_campaign_id,\n        sum(exp_generosity_cost) as exp_generosity_cost,\n        sum(generosity_cost) as generosity_cost\n    FROM fbg_analytics.product_and_customer.oc_generosity_cost\n    GROUP BY ALL\n)\n\nSELECT\n    a.acco_id,\n    j.jurisdiction_code,\n    a.id as account_statements_id,\n    COALESCE(cast(replace(a.ext_bonus_campaign_id,\'\',null) as int),a.bonus_campaign_id) as bonus_campaign_id,\n    b."Bonus Code",\n    b."Description",\n    b."Bonus Origin",\n    b."Bonus Category",\n    b."SubCategory",\n    b."Series",\n    (convert_timezone(\'UTC\',\'America/Anchorage\', a.trans_date)) AS date,\n    \'bonus winnings\' as transaction,\n    \'free_spin\' as promo_type,\n    a.amount,\n    gc.generosity_cost as after_tax_amount,\n    b.referee_account_id\nFROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS as a\ninner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS as j\non a.jurisdictions_id = j.id\nINNER JOIN FBG_ANALYTICS.CASINO.free_spin_awarded_stg as b\nON a.bet_id = b.bet_id\nLEFT JOIN generosity_cost gc\non a.bet_id = gc.bet_id and a.bonus_campaign_id = gc.bonus_campaign_id\nWHERE a.trans in (\'SETTLEMENT\',\'UNSETTLEMENT\')\nAND (a.amount <> 0 or gc.generosity_cost <> 0)\n\nunion all\n\nSELECT\n    a.acco_id,\n    j.jurisdiction_code,\n    a.id as account_statements_id,\n    COALESCE(cast(replace(a.ext_bonus_campaign_id,\'\',null) as int),a.bonus_campaign_id) as bonus_campaign_id,\n    b."Bonus Code",\n    b."Description",\n    b."Bonus Origin",\n    b."Bonus Category",\n    b."SubCategory",\n    b."Series",\n    (convert_timezone(\'UTC\',\'America/Anchorage\', a.trans_date)) AS date,\n    \'bonus expected winnings\' as transaction,\n    \'free_spin\' as promo_type,\n    e.expected_payout as amount,\n    gc.exp_generosity_cost as after_tax_amount,\n    b.referee_account_id\nFROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS as a\ninner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS as j\non a.jurisdictions_id = j.id\nINNER JOIN FBG_ANALYTICS.CASINO.free_spin_awarded_stg as b\nON a.bet_id = b.bet_id\ninner join FBG_ANALYTICS.CASINO.casino_bet_expected_payouts_stg e\non a.bet_id = e.bet_id and a.bonus_campaign_id = e.bonus_campaign_id \nLEFT JOIN generosity_cost gc\non a.bet_id = gc.bet_id and a.bonus_campaign_id = gc.bonus_campaign_id\nWHERE a.trans in (\'SETTLEMENT\',\'UNSETTLEMENT\')',NULL,'01c39a04-0212-6dbe-24dd-0703193593b3','Thread-13 (worker)','table','{"_message": "SUCCESS 364161931", "code": "SUCCESS", "rows_affected": 364161931, "query_id": "01c39a04-0212-6dbe-24dd-0703193593b3", "rows_inserted": 364161931, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.casino_credit_payout_stg','model.dbt_casino.casino_credit_payout_stg','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
  current_timestamp::timestamp
,'casino_credit_payout_stg','SUCCESS 387346458','success','model',141.1834352016449,'2026-04-09T21:25:22.407658Z','2026-04-09T21:27:43.511594Z','2026-04-09T21:25:22.403482Z','2026-04-09T21:25:22.407062Z',387346458,False,'WITH generosity_cost as (\n    SELECT\n        bet_id,\n        bonus_campaign_id,\n        sum(exp_generosity_cost) as exp_generosity_cost,\n        sum(generosity_cost) as generosity_cost\n    FROM fbg_analytics.product_and_customer.oc_generosity_cost\n    GROUP BY ALL\n)\n\nSELECT\n    a.acco_id,\n    j.jurisdiction_code,\n    a.id as account_statements_id,\n    b.bonus_campaign_id,\n    b."Bonus Code",\n    b."Description",\n    b."Bonus Origin",\n    b."Bonus Category",\n    b."SubCategory",\n    b."Series",\n    (convert_timezone(\'UTC\',\'America/Anchorage\', a.trans_date)) AS date,\n    \'bonus winnings\' as transaction,\n    \'casino_credit\' as promo_type,\n    a.amount * coalesce(c.attrib_perc,1) as amount,\n    gc.generosity_cost * coalesce(c.attrib_perc,1) as after_tax_amount,\n    null as referee_account_id\nFROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS as a\ninner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS as j\non a.jurisdictions_id = j.id\nINNER JOIN FBG_ANALYTICS.CASINO.casino_credit_awarded_stg as b\nON a.bet_id = b.bet_id\nleft join FBG_ANALYTICS.CASINO.casino_credit_payout_ratios_stg c\non a.bet_id = c.bet_id and b.bonus_campaign_id = c.bonus_campaign_id\nLEFT JOIN generosity_cost gc\non a.bet_id = gc.bet_id and b.bonus_campaign_id = gc.bonus_campaign_id\nWHERE a.trans in (\'SETTLEMENT\',\'UNSETTLEMENT\')\nAND (a.amount <> 0 or gc.generosity_cost <> 0)\n\nunion all\n\nSELECT\n    a.acco_id,\n    j.jurisdiction_code,\n    a.id as account_statements_id,\n    b.bonus_campaign_id,\n    b."Bonus Code",\n    b."Description",\n    b."Bonus Origin",\n    b."Bonus Category",\n    b."SubCategory",\n    b."Series",\n    (convert_timezone(\'UTC\',\'America/Anchorage\', a.trans_date)) AS date,\n    \'bonus expected winnings\' as transaction,\n    \'casino_credit\' as promo_type,\n    e.expected_payout as amount,\n    gc.exp_generosity_cost as after_tax_amount,\n    null as referee_account_id\nFROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS as a\ninner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS as j\non a.jurisdictions_id = j.id\nINNER JOIN FBG_ANALYTICS.CASINO.casino_credit_awarded_stg as b\nON a.bet_id = b.bet_id\ninner join FBG_ANALYTICS.CASINO.casino_bet_expected_payouts_stg e\non a.bet_id = e.bet_id and b.bonus_campaign_id = e.bonus_campaign_id \nLEFT JOIN generosity_cost gc\non a.bet_id = gc.bet_id and b.bonus_campaign_id = gc.bonus_campaign_id\nWHERE a.trans in (\'SETTLEMENT\',\'UNSETTLEMENT\')',NULL,'01c39a05-0212-644a-24dd-070319356e9b','Thread-12 (worker)','table','{"_message": "SUCCESS 387346458", "code": "SUCCESS", "rows_affected": 387346458, "query_id": "01c39a05-0212-644a-24dd-070319356e9b", "rows_inserted": 387346458, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('906951ca-6255-46c9-a666-4129ac48200c.model.dbt_casino.casino_promotions_ledger','model.dbt_casino.casino_promotions_ledger','906951ca-6255-46c9-a666-4129ac48200c','2026-04-09 21:36:11',
  current_timestamp::timestamp
,'casino_promotions_ledger','SUCCESS 9247061526','success','model',470.4517114162445,'2026-04-09T21:27:43.599029Z','2026-04-09T21:35:33.899947Z','2026-04-09T21:27:43.592123Z','2026-04-09T21:27:43.598408Z',9247061526,False,'WITH transactions_lkp as (--noqa: disable=all\n    select * from (values (\'bonus awarded\'), (\'bonus used\'), (\'bonus winnings\'), (\'bonus expected winnings\')) as transactions (transaction)\n),\n\ncash_back AS \n(\n    SELECT\n        a.acco_id,\n        j.jurisdiction_code,\n        a.id as account_statements_id,\n        CAST(999997 as varchar) as bonus_campaign_id,\n        CASE WHEN description = \'IGT\' then \'IGT Casino Cash Back\' else \'Casino Cash Back\' end as "Bonus Code",\n        \'Casino Cash Back\' as "Description",\n        try_parse_json(a.additional_info):bonusOrigin::varchar as "Bonus Origin", ---NEW\n        \'Retention\' as "Bonus Category",\n        \'VIP Cash Back\' as "SubCategory",\n        \'Cash Back\' as "Series",\n        (convert_timezone(\'UTC\',\'America/Anchorage\',trans_date)) AS date,\n        t.transaction,\n        \'cash_back\' as promo_type,\n        a.amount,\n        case when t.transaction in (\'bonus winnings\', \'bonus expected winnings\') then a.amount else 0 end as after_tax_amount,\n        null as referee_account_id\n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS AS a\n    inner join FBG_SOURCE.OSB_SOURCE.JURISDICTIONS as j\n    on a.jurisdictions_id = j.id\n    inner join transactions_lkp t\n    on 1 = 1\n    WHERE a.trans IN (\'BONUS_MARKETING\')\n        AND (upper(regexp_replace(description,\' \')) in (\'CASINOCASHBACK\',\'CASINO CASHBACK\',\'CASINO CASH BACK\',\'IGT\')\n        OR (parse_json(a.additional_info):bonusType::varchar = \'Casino\'))\n),\n\nfanatics_one_credits as (\n    SELECT\n        acco_id,\n        null jurisdiction_code,\n        null account_statements_id,\n        null bonus_campaign_id,\n        \'Fanatics One Credit\' as "Bonus Code",\n        \'Fanatics One Credit\' as "Description",\n        \'Fanatics One Credit\' as "Bonus Origin", ---NEW\n        \'Retention\' as "Bonus Category",\n        \'Fanatics One Credit\' as "SubCategory",\n        \'Fanatics One Credit\' as "Series",\n        earned_date::timestamp AS date,\n        t.transaction,\n        \'fanatics_one_credit\' as promo_type,\n        oc_distribution as amount,\n        case when t.transaction in (\'bonus winnings\', \'bonus expected winnings\') then oc_distribution else 0 end as after_tax_amount,\n        null as referee_account_id\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.DAILY_ONE_CREDIT_ISSUANCE f1\n    inner join transactions_lkp t\n    on 1 = 1\n),\n\nfc_awarded AS (\n    SELECT\n        acco_id,\n        earn_jurisdiction_code as jurisdiction_code,\n        null account_statements_id,\n        bonus_campaign_id,\n        "Bonus Code",\n        "Description",\n        "Bonus Origin",\n        "Bonus Category",\n        "SubCategory",\n        "Series",\n        earn_date_alk as date,\n        \'bonus awarded\' as transaction,\n        \'fancash\' as promo_type,\n        sum(proportional_earn) as amount,\n        sum(0) as after_tax_amount,\n        referee_account_id\n    FROM FBG_ANALYTICS.CASINO.fc_earns_and_burns_stg\n    group by all\n),\n\nfc_used AS (\n    SELECT\n        acco_id,\n        burn_jurisdiction_code as jurisdiction_code,\n        null account_statements_id,\n        bonus_campaign_id,\n        "Bonus Code",\n        "Description",\n        "Bonus Origin",\n        "Bonus Category",\n        "SubCategory",\n        "Series",\n        burn_date_alk as date,\n        \'bonus used\' as transaction,\n        \'fancash\' as promo_type,\n        sum(burned_amount) as amount,\n        sum(0) as after_tax_amount,\n        referee_account_id\n    FROM FBG_ANALYTICS.CASINO.fc_earns_and_burns_stg\n    where burn_site = \'FBG\'\n    group by all\n),\n\nfc_payout AS  (\n    SELECT\n        acco_id,\n        burn_jurisdiction_code as jurisdiction_code,\n        null account_statements_id,\n        bonus_campaign_id,\n        "Bonus Code",\n        "Description",\n        "Bonus Origin",\n        "Bonus Category",\n        "SubCategory",\n        "Series",\n        payout_date_alk as date,\n        \'bonus winnings\' as transaction,\n        \'fancash\' as promo_type,\n        sum(proportional_payout) as amount,\n        sum(proportional_generosity_cost) as after_tax_amount,\n        referee_account_id\n    FROM FBG_ANALYTICS.CASINO.fc_costs_stg_incremental\n    where burn_site = \'FBG\'\n    group by all\n),\n\nfc_epayout AS  (\n    SELECT\n        acco_id,\n        burn_jurisdiction_code as jurisdiction_code,\n        null account_statements_id,\n        bonus_campaign_id,\n        "Bonus Code",\n        "Description",\n        "Bonus Origin",\n        "Bonus Category",\n        "SubCategory",\n        "Series",\n        payout_date_alk as date,\n        \'bonus expected winnings\' as transaction,\n        \'fancash\' as promo_type,\n        sum(proportional_epayout) as amount,\n        sum(proportional_exp_generosity_cost) as after_tax_amount,\n        referee_account_id\n    FROM FBG_ANALYTICS.CASINO.fc_costs_stg_incremental\n    where burn_site = \'FBG\'\n    group by all\n),\n\nfc_expired AS (\n    SELECT\n        acco_id,\n        earn_jurisdiction_code as jurisdiction_code,\n        null account_statements_id,\n        bonus_campaign_id,\n        "Bonus Code",\n        "Description",\n        "Bonus Category",\n        "Bonus Origin",\n        "SubCategory",\n        "Series",\n        expiration_date_alk as date,\n        \'bonus expired\' as transaction,\n        \'fancash\' as promo_type,\n        sum(proportional_earn) as amount,\n        sum(0) as after_tax_amount,\n        referee_account_id\n    FROM FBG_ANALYTICS.CASINO.fc_earns_and_burns_stg\n    where expiration_date_alk < convert_timezone(\'UTC\',\'America/Anchorage\',sysdate())\n    group by all\n),\n\nfc_commerce_used AS (\n    SELECT\n        acco_id,\n        burn_jurisdiction_code as jurisdiction_code,\n        null account_statements_id,\n        bonus_campaign_id,\n        "Bonus Code",\n        "Description",\n        "Bonus Origin",\n        "Bonus Category",\n        "SubCategory",\n        "Series",\n        burn_date_alk as date,\n        \'bonus used\' as transaction,\n        \'fancash_commerce\' as promo_type,\n        sum(burned_amount) as amount,\n        sum(0) as after_tax_amount,\n        referee_account_id\n    FROM FBG_ANALYTICS.CASINO.fc_earns_and_burns_stg\n    where burn_site = \'Commerce\'\n    group by all\n),\n\nfc_commerce_payout_epayout AS (\n    SELECT\n        acco_id,\n        burn_jurisdiction_code as jurisdiction_code,\n        null account_statements_id,\n        bonus_campaign_id,\n        "Bonus Code",\n        "Description",\n        "Bonus Origin",\n        "Bonus Category",\n        "SubCategory",\n        "Series",\n        payout_date_alk as date,\n        t.transaction,\n        \'fancash_commerce\' as promo_type,\n        sum(case when transaction = \'bonus winnings\' then proportional_payout\n                 when transaction = \'bonus expected winnings\' then proportional_epayout\n                 else 0\n                 end) as amount,\n        sum(case when transaction = \'bonus winnings\' then proportional_generosity_cost\n                 when transaction = \'bonus expected winnings\' then proportional_exp_generosity_cost\n                 else 0\n                 end) as after_tax_amount,\n        referee_account_id\n    FROM FBG_ANALYTICS.CASINO.fc_costs_stg_incremental\n    inner join transactions_lkp t\n    on 1 = 1 and transaction in (\'bonus winnings\',\'bonus expected winnings\')\n    where burn_site = \'Commerce\'\n    group by all\n),\n\nbonus AS (\n    SELECT * FROM cash_back\n    UNION ALL\n    SELECT * FROM fanatics_one_credits\n    UNION ALL\n    SELECT * exclude(bet_id, account_bonus_id) FROM FBG_ANALYTICS.CASINO.free_spin_awarded_stg\n    UNION ALL\n    SELECT * FROM FBG_ANALYTICS.CASINO.free_spin_payout_stg\n    UNION ALL\n    SELECT * exclude(bet_id, account_bonus_id) FROM FBG_ANALYTICS.CASINO.casino_credit_awarded_stg where bonus_campaign_id <> 45803\n    UNION ALL\n    SELECT * FROM FBG_ANALYTICS.CASINO.casino_credit_payout_stg where bonus_campaign_id <> 45803\n    UNION ALL\n    SELECT * exclude(bet_id) FROM FBG_ANALYTICS.CASINO.osb_bonus_bet_awarded_stg \n    UNION ALL\n    SELECT * FROM FBG_ANALYTICS.CASINO.osb_bonus_bet_payout_stg\n    UNION ALL\n    SELECT * FROM fc_awarded\n    UNION ALL\n    SELECT * FROM fc_used\n    UNION ALL\n    SELECT * FROM fc_payout\n    UNION ALL\n    SELECT * FROM fc_epayout\n    UNION ALL\n    SELECT * FROM fc_expired\n    UNION ALL\n    SELECT * FROM fc_commerce_used\n    UNION ALL\n    SELECT * FROM fc_commerce_payout_epayout\n    UNION ALL\n    SELECT * exclude(bet_id) FROM FBG_ANALYTICS.CASINO.fc_jackpots_awarded_stg\n    UNION ALL\n    SELECT * FROM FBG_ANALYTICS.CASINO.fc_jackpots_costs_stg\n    UNION ALL\n    SELECT * FROM FBG_ANALYTICS.CASINO.fc_jackpots_drops_stg\n),\n\nstaging AS (\n    SELECT\n        *,\n        date(date) as day,\n        DATE(date_trunc(\'week\', date)) AS week,\n        DATE(date_trunc(\'month\', date)) AS month\n    FROM bonus \n)\n\nselect\n    CAST(truncate(s.acco_id) as int) AS ACCO_ID,\n    jurisdiction_code,\n    ACCOUNT_STATEMENTS_ID,\n    \'casino\' as product,\n    CAST(truncate(bonus_campaign_id) as int) AS BONUS_CAMPAIGN_ID,\n    "Bonus Code",\n    "Description",\n    "Bonus Origin",\n    case when "Bonus Origin" = \'F2PGAME\' and s.day <= cm.casino_ftu_date_alk::date + 6 then \'Acquisition\' else "Bonus Category" end "Bonus Category",\n    "SubCategory",\n    "Series",\n    DATE,\n    TRANSACTION,\n    PROMO_TYPE,\n    AMOUNT,\n    after_tax_amount,\n    cast(referee_account_id as int) as referee_account_id,\n    DAY,\n    WEEK,\n    MONTH,\n    current_timestamp() as last_updated\nfrom staging s\ninner join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART cm\non s.acco_id = cm.acco_id\nwhere "Bonus Category" <> \'TEST\' or "Bonus Category" is null',NULL,'01c39a07-0212-6e7d-24dd-07031936283b','Thread-9 (worker)','table','{"_message": "SUCCESS 9247061526", "code": "SUCCESS", "rows_affected": 9247061526, "query_id": "01c39a07-0212-6e7d-24dd-07031936283b", "rows_inserted": 9247061526, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}')
